"use client";

import { forwardRef } from "react";
import type { MediaLibrary01Handle, MediaLibrary01Props } from "./types";
import { MediaLibraryRoot } from "./parts/media-library-root";
import { MediaLibraryToolbar } from "./parts/library-toolbar";
import { MediaLibraryQuotaBar } from "./parts/quota-bar";
import { MediaLibraryTypeFilters } from "./parts/type-filters";
import { MediaLibraryBreadcrumbs } from "./parts/breadcrumbs";
import { MediaLibrarySidebar } from "./parts/sidebar";
import { MediaLibraryFolderRow } from "./parts/folder-row";
import { MediaLibraryFileGrid } from "./parts/file-grid";
import { MediaLibraryDetailsPane } from "./parts/details-pane";
import { MediaLibraryLightbox } from "./parts/preview-lightbox";

/**
 * Tier A — the batteries-included Google-Drive-style media library. A thin
 * assembly of `<MediaLibraryRoot>` + the canonical parts, gated by the
 * `show*` / `preview` toggles. For a lighter, hand-composed version, drop down
 * to `<MediaLibraryRoot>` + the individual parts (all exported).
 */
export const MediaLibrary01 = forwardRef<MediaLibrary01Handle, MediaLibrary01Props>(
  function MediaLibrary01(props, ref) {
    const {
      showQuota = true,
      showTypeFilters = true,
      showSidebar = true,
      preview = "both",
      className,
      ...rootProps
    } = props;

    const showPane = preview === "pane" || preview === "both";
    const showLightbox = preview === "lightbox" || preview === "both";

    return (
      <MediaLibraryRoot
        ref={ref}
        preview={preview}
        className={className}
        {...rootProps}
      >
        {showQuota ? <MediaLibraryQuotaBar /> : null}
        <MediaLibraryToolbar />
        {showTypeFilters ? <MediaLibraryTypeFilters /> : null}
        <MediaLibraryBreadcrumbs />
        <div className="flex min-h-0 gap-4">
          {showSidebar ? <MediaLibrarySidebar /> : null}
          <div className="flex min-w-0 flex-1 flex-col gap-5">
            <MediaLibraryFolderRow />
            <MediaLibraryFileGrid />
          </div>
          {showPane ? <MediaLibraryDetailsPane /> : null}
        </div>
        {showLightbox ? <MediaLibraryLightbox /> : null}
      </MediaLibraryRoot>
    );
  },
);

// --- Tail re-export band (F-01): a future cross-procomp consumer imports public
// types from this `.tsx` entry, never a `/types` subpath. ---
export type {
  FsNode,
  FsNodeType,
  MediaNode,
  MediaPreviewKind,
  MediaFilterCategory,
  MediaLibrary01Storage,
  MediaUploadItem,
  MediaUploadStatus,
  MediaUploadProgressFn,
  MediaLibrary01Labels,
  MediaLibraryPreviewMode,
  MediaLibraryRootProps,
  MediaLibrary01Props,
  MediaLibrary01Handle,
} from "./types";

// Tier A — batteries-included assembly
export { MediaLibrary01 } from "./media-library-01";

// Tier B — headless provider + context-connected parts (compose your own)
export { MediaLibraryRoot } from "./parts/media-library-root";
export { MediaLibraryToolbar } from "./parts/library-toolbar";
export { MediaLibraryQuotaBar } from "./parts/quota-bar";
export { MediaLibraryTypeFilters } from "./parts/type-filters";
export { MediaLibraryBreadcrumbs } from "./parts/breadcrumbs";
export { MediaLibrarySidebar } from "./parts/sidebar";
export { MediaLibraryFolderRow } from "./parts/folder-row";
export { MediaLibraryFileGrid } from "./parts/file-grid";
export { MediaLibraryDetailsPane } from "./parts/details-pane";
export { MediaLibraryLightbox } from "./parts/preview-lightbox";
export { MediaLibraryUploadOverlay } from "./parts/upload-overlay";

// Tier C — standalone primitives (no context)
export { FilePreview } from "./parts/file-preview";
export { FilePreviewLightbox } from "./parts/preview-lightbox";
export { FileCard } from "./parts/file-card";
export { FolderCard } from "./parts/folder-card";
export { QuotaBar } from "./parts/quota-bar";
export { UploadOverlay } from "./parts/upload-overlay";
export { FileKindBadge, PreviewKindIcon } from "./parts/file-visuals";

// Hook + helpers
export { useMediaLibrary } from "./hooks/use-media-library";
export type { MediaLibraryContextValue } from "./hooks/use-media-library";
export { resolvePreviewKind, isTextKind, extOf } from "./lib/preview-kind";
export {
  filterCategoryForNode,
  filterCategoryForKind,
  computeFilterCounts,
} from "./lib/filter-category";
export { formatBytes, formatRelativeTime } from "./lib/format";

// Defaults
export { DEFAULT_MEDIA_LIBRARY_LABELS } from "./types";

// Part prop types
export type { QuotaBarProps } from "./parts/quota-bar";
export type { FileCardProps } from "./parts/file-card";
export type { FolderCardProps } from "./parts/folder-card";
export type { FilePreviewProps } from "./parts/file-preview";
export type { FilePreviewLightboxProps } from "./parts/preview-lightbox";

// Public types
export type {
  FsNode,
  FsNodeType,
  MediaNode,
  MediaPreviewKind,
  MediaFilterCategory,
  MediaLibrary01Storage,
  MediaUploadItem,
  MediaUploadStatus,
  MediaUploadProgressFn,
  MediaLibrary01Labels,
  MediaLibraryPreviewMode,
  MediaLibraryRootProps,
  MediaLibrary01Props,
  MediaLibrary01Handle,
} from "./types";

import type { ReactNode, Ref } from "react";

/**
 * FsNode is DECLARED LOCALLY (not imported from file-tree).
 *
 * VERIFIED 2026-06-09: `file-tree.tsx` only *imports* `FsNode` (no tail
 * re-export band), so a `.tsx`-entry type import would fail; a `/types`
 * subpath import trips the F-S1 slug-rewriter; and adding a tail band to
 * `file-tree.tsx` would modify a shipped component (forbidden). Re-declaring
 * the (tiny, stable) interface keeps file-tree UNTOUCHED and zeroes the
 * cross-procomp *type* surface — structural typing bridges at the composed
 * `<FileTree nodes={...}>` boundary (the media-carousel-editor-01
 * "define your own type locally" precedent).
 */
export type FsNodeType = "file" | "folder";

export interface FsNode {
  id: string;
  name: string;
  type: FsNodeType;
  parentId?: string | null;
  /** `undefined` ⇒ lazy-load trigger; `[]` ⇒ known-empty; `FsNode[]` ⇒ loaded. */
  children?: FsNode[];
  ext?: string;
  /** Bytes. */
  size?: number;
  /** ISO 8601. */
  modifiedAt?: string;
  icon?: ReactNode;
  meta?: Record<string, unknown>;
}

/** Which viewer a file maps to in the preview dispatcher. */
export type MediaPreviewKind =
  | "image"
  | "video"
  | "pdf"
  | "code"
  | "json"
  | "text"
  | "markdown"
  | "unknown";

/** Type-filter chip identity. */
export type MediaFilterCategory = "all" | "images" | "video" | "pdfs" | "docs";

/**
 * A media-library node. Strict superset of {@link FsNode} — every added field
 * is optional, so any `FsNode[]` is assignable to `MediaNode[]` (interop with
 * file-tree / file-manager preserved).
 */
export interface MediaNode extends FsNode {
  /** Canonical asset URL — the preview source. */
  url?: string;
  /** Poster / thumbnail for the grid (images fall back to `url`). */
  thumbnailUrl?: string;
  /** Authoritative MIME type; `ext` is the fallback for kind resolution. */
  mimeType?: string;
  width?: number;
  height?: number;
  owner?: string;
  children?: MediaNode[];
}

export interface MediaLibrary01Storage {
  /** Bytes used. */
  used: number;
  /** Bytes total. */
  total: number;
}

/**
 * Fires repeatedly during a single file's upload (0–100); consumer-driven.
 * `onUpload` is invoked once per file, so the progress fn is pre-bound to that
 * file's optimistic item — the consumer just reports its percent.
 */
export type MediaUploadProgressFn = (pct: number) => void;

/** Internal status of an optimistic upload placeholder. */
export type MediaUploadStatus = "uploading" | "error";

/** An in-flight optimistic upload item shown in the grid before it resolves. */
export interface MediaUploadItem {
  tempId: string;
  name: string;
  kind: MediaPreviewKind;
  pct: number;
  status: MediaUploadStatus;
  /** Object URL for a local preview while uploading (owned + revoked by the lib). */
  previewUrl?: string;
  error?: string;
  /** The folder the upload targets. */
  targetFolderId: string | null;
}

export interface MediaLibrary01Labels {
  title?: string;
  searchPlaceholder?: string;
  uploadButton?: string;
  newFolderButton?: string;
  foldersHeading?: string;
  filesHeading?: string;
  libraryHeading?: string;
  /** Template with `{used}` and `{total}`, e.g. "{used} of {total} used". */
  quotaUsed?: string;
  filterAll?: string;
  filterImages?: string;
  filterVideo?: string;
  filterPdfs?: string;
  filterDocs?: string;
  emptyFolder?: string;
  emptyLibrary?: string;
  dropToUpload?: string;
  previewLoading?: string;
  previewError?: string;
  noPreview?: string;
  download?: string;
  retry?: string;
  // context-menu verbs
  open?: string;
  preview?: string;
  rename?: string;
  move?: string;
  cut?: string;
  copy?: string;
  paste?: string;
  delete?: string;
  // a11y
  /** Template with `{name}` and `{kind}`. */
  itemAria?: string;
  /** Template with `{name}`. */
  uploadingAria?: string;
  /** Template with `{count}`. */
  selectedAria?: string;
  prev?: string;
  next?: string;
  close?: string;
}

export type MediaLibraryPreviewMode = "pane" | "lightbox" | "both" | false;

/**
 * Shared data + handler surface. {@link MediaLibrary01Props} adds the chrome
 * toggles on top of this; {@link MediaLibraryRootProps} is this verbatim
 * (composition replaces the toggles).
 */
export interface MediaLibraryRootProps {
  nodes: MediaNode[];
  currentFolderId?: string | null;
  defaultCurrentFolderId?: string | null;
  onCurrentFolderChange?: (folderId: string | null) => void;
  onLoadChildren?: (folderId: string) => Promise<MediaNode[]>;

  storage?: MediaLibrary01Storage;

  selectedIds?: Set<string>;
  defaultSelectedIds?: Set<string>;
  onSelectedChange?: (ids: Set<string>) => void;

  // mutation operations (omit to hide the affordance).
  // `onUpload` is called once per file; `progress` reports that file's percent.
  onUpload?: (
    files: File[],
    targetFolderId: string | null,
    progress: MediaUploadProgressFn,
  ) => Promise<MediaNode[]>;
  onMove?: (ids: string[], targetFolderId: string | null) => void;
  onRename?: (id: string, name: string) => void;
  onDelete?: (ids: string[]) => void;
  onCreateFolder?: (parentId: string | null, name: string) => void;
  onDownload?: (ids: string[]) => void;
  validateRename?: (id: string, name: string) => string | null;

  // preview content sourcing (URL-based; text kinds fetched by the lib)
  resolveTextContent?: (node: MediaNode) => Promise<string>;
  /**
   * Override the pdf.js worker URL used by the composed pdf-viewer. The viewer
   * defaults to a unpkg CDN worker; pass a self-hosted path
   * (e.g. "/pdf.worker.min.mjs") for offline / locked-down environments.
   */
  pdfWorkerSrc?: string;
  onPreviewOpen?: (id: string) => void;
  onPreviewClose?: () => void;

  // behaviour
  enableUploadDrop?: boolean;
  enableInternalDrag?: boolean;
  enableContextMenu?: boolean;
  /** Whether opening a file shows a preview at all (default "both"). */
  preview?: MediaLibraryPreviewMode;
  virtualizeThreshold?: number;

  labels?: Partial<MediaLibrary01Labels>;
  children?: ReactNode;
  className?: string;
  ref?: Ref<MediaLibrary01Handle>;
}

/** The batteries-included assembly: root surface + chrome toggles. */
export interface MediaLibrary01Props
  extends Omit<MediaLibraryRootProps, "children"> {
  showQuota?: boolean;
  showTypeFilters?: boolean;
  showSidebar?: boolean;
}

export interface MediaLibrary01Handle {
  navigateTo: (folderId: string | null) => void;
  refresh: (folderId?: string | null) => void;
  openPreview: (id: string) => void;
  closePreview: () => void;
  /** Opens the OS file picker for the current folder. */
  triggerUpload: () => void;
  getSelectedIds: () => string[];
  clearSelection: () => void;
}

export const DEFAULT_MEDIA_LIBRARY_LABELS: Required<MediaLibrary01Labels> = {
  title: "Media library",
  searchPlaceholder: "Search this folder",
  uploadButton: "Upload",
  newFolderButton: "New folder",
  foldersHeading: "Folders",
  filesHeading: "Files",
  libraryHeading: "Library",
  quotaUsed: "{used} of {total} used",
  filterAll: "All",
  filterImages: "Images",
  filterVideo: "Video",
  filterPdfs: "PDFs",
  filterDocs: "Docs",
  emptyFolder: "This folder is empty",
  emptyLibrary: "No media yet — upload to get started",
  dropToUpload: "Drop files to upload",
  previewLoading: "Loading preview…",
  previewError: "Couldn't load this file",
  noPreview: "No preview available",
  download: "Download",
  retry: "Retry",
  open: "Open",
  preview: "Preview",
  rename: "Rename",
  move: "Move",
  cut: "Cut",
  copy: "Copy",
  paste: "Paste",
  delete: "Delete",
  itemAria: "{name}, {kind}",
  uploadingAria: "Uploading {name}",
  selectedAria: "{count} selected",
  prev: "Previous",
  next: "Next",
  close: "Close",
};

import { useCallback, useEffect, useRef, useState } from "react";

interface UseControllableStateOpts<T> {
  /** Controlled value. When provided, state is fully controlled by parent. */
  value?: T;
  /** Initial value for uncontrolled mode. */
  defaultValue: T;
  /** Fires on every state change (both modes). */
  onChange?: (next: T) => void;
  /** Component name used in dev warnings. */
  componentName: string;
  /** Prop name used in dev warnings (e.g., `"selectedIds"`). */
  valuePropName: string;
}

/**
 * Controlled+uncontrolled state helper. Sealed copy of the proven generic used
 * across the library (account-switcher-01, code-block, media-carousel-editor-01)
 * — registry portability bans a shared cross-component module, so each procomp
 * vendors its own. Locks the mode at first render and dev-warns on mode-flip or
 * controlled-without-onChange.
 */
export function useControllableState<T>({
  value,
  defaultValue,
  onChange,
  componentName,
  valuePropName,
}: UseControllableStateOpts<T>): readonly [T, (next: T) => void] {
  const [internal, setInternal] = useState<T>(defaultValue);
  const isControlled = value !== undefined;
  const onChangeRef = useRef(onChange);
  useEffect(() => {
    onChangeRef.current = onChange;
  });

  const wasControlledRef = useRef(isControlled);
  useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    if (wasControlledRef.current !== isControlled) {
      console.warn(
        `[${componentName}] \`${valuePropName}\` switched from ${
          wasControlledRef.current ? "controlled" : "uncontrolled"
        } to ${
          isControlled ? "controlled" : "uncontrolled"
        } mode. Components should not switch modes mid-life; pick one at mount.`,
      );
      wasControlledRef.current = isControlled;
    }
  }, [isControlled, componentName, valuePropName]);

  const current = isControlled ? (value as T) : internal;

  const set = useCallback(
    (next: T) => {
      if (!isControlled) setInternal(next);
      onChangeRef.current?.(next);
    },
    [isControlled],
  );

  return [current, set] as const;
}

import { useCallback, useMemo, useRef, useState } from "react";
import type { MediaNode } from "../types";

/** Recursively replace a folder's `children` with cache-loaded children. */
function mergeCache(
  nodes: MediaNode[],
  cache: Record<string, MediaNode[]>,
): MediaNode[] {
  return nodes.map((node) => {
    if (node.type !== "folder") return node;
    const loaded = cache[node.id];
    const children = loaded ?? node.children;
    return {
      ...node,
      children: children ? mergeCache(children, cache) : children,
    };
  });
}

export interface LazyChildrenApi {
  /** Root nodes with lazily-loaded children merged in. */
  nodes: MediaNode[];
  /** Trigger a load for a folder if not cached / in flight. */
  ensureLoaded: (folderId: string) => void;
  /** Drop a folder's cache (or all) so the next visit re-loads. */
  invalidate: (folderId?: string | null) => void;
  loadingIds: ReadonlySet<string>;
  errorIds: Record<string, string>;
}

/**
 * Lazy-children manager: caches `onLoadChildren` results, merges them into the
 * tree, tracks per-folder loading + error. No-op when `onLoadChildren` is
 * absent (the consumer supplies the full tree inline).
 */
export function useLazyChildren(
  rootNodes: MediaNode[],
  onLoadChildren?: (folderId: string) => Promise<MediaNode[]>,
): LazyChildrenApi {
  const [cache, setCache] = useState<Record<string, MediaNode[]>>({});
  const [loadingIds, setLoadingIds] = useState<Set<string>>(() => new Set());
  const [errorIds, setErrorIds] = useState<Record<string, string>>({});
  const inflight = useRef<Set<string>>(new Set());

  const ensureLoaded = useCallback(
    (folderId: string) => {
      if (!onLoadChildren) return;
      if (cache[folderId] || inflight.current.has(folderId)) return;
      inflight.current.add(folderId);
      setLoadingIds((prev) => new Set(prev).add(folderId));
      setErrorIds((prev) => {
        if (!(folderId in prev)) return prev;
        const next = { ...prev };
        delete next[folderId];
        return next;
      });
      onLoadChildren(folderId)
        .then((children) => {
          setCache((prev) => ({ ...prev, [folderId]: children }));
        })
        .catch((err: unknown) => {
          setErrorIds((prev) => ({
            ...prev,
            [folderId]: (err as Error)?.message || "Failed to load",
          }));
        })
        .finally(() => {
          inflight.current.delete(folderId);
          setLoadingIds((prev) => {
            const next = new Set(prev);
            next.delete(folderId);
            return next;
          });
        });
    },
    [onLoadChildren, cache],
  );

  const invalidate = useCallback((folderId?: string | null) => {
    if (folderId == null) {
      setCache({});
      setErrorIds({});
      return;
    }
    setCache((prev) => {
      const next = { ...prev };
      delete next[folderId];
      return next;
    });
    setErrorIds((prev) => {
      const next = { ...prev };
      delete next[folderId];
      return next;
    });
  }, []);

  const nodes = useMemo(() => mergeCache(rootNodes, cache), [rootNodes, cache]);

  return { nodes, ensureLoaded, invalidate, loadingIds, errorIds };
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type RefObject,
} from "react";
import {
  DEFAULT_MEDIA_LIBRARY_LABELS,
  type MediaFilterCategory,
  type MediaLibrary01Labels,
  type MediaLibrary01Storage,
  type MediaLibraryPreviewMode,
  type MediaLibraryRootProps,
  type MediaNode,
  type MediaUploadItem,
} from "../types";
import {
  computeFilterCounts,
  nodeMatchesFilter,
  type MediaFilterCounts,
} from "../lib/filter-category";
import { buildParentMap, canDropInto, findNode } from "../lib/drag";
import { useControllableState } from "./use-controllable-state";
import { useLazyChildren } from "./use-lazy-children";
import { useSelection, type SelectionApi } from "./use-selection";
import { useUpload } from "./use-upload";

export interface MediaClipboard {
  kind: "cut" | null;
  ids: string[];
}

export interface MediaLibraryContextValue {
  labels: Required<MediaLibrary01Labels>;

  // current-folder view
  nodes: MediaNode[];
  currentFolderId: string | null;
  currentFolder: MediaNode | null;
  path: MediaNode[];
  folders: MediaNode[];
  files: MediaNode[];
  filterCounts: MediaFilterCounts;
  uploads: MediaUploadItem[];
  loadingChildren: boolean;
  loadError: string | null;

  // ui state
  filter: MediaFilterCategory;
  setFilter: (f: MediaFilterCategory) => void;
  searchQuery: string;
  setSearchQuery: (q: string) => void;

  storage?: MediaLibrary01Storage;

  // selection
  selectedIds: Set<string>;
  selection: SelectionApi;
  visibleIds: string[];

  // clipboard (cut → move on paste; copy deferred to v0.2)
  clipboard: MediaClipboard;
  cut: (ids: string[]) => void;
  paste: () => void;

  // navigation
  navigateTo: (folderId: string | null) => void;
  navigateUp: () => void;
  refresh: (folderId?: string | null) => void;

  // preview
  previewId: string | null;
  previewNode: MediaNode | null;
  openPreview: (id: string) => void;
  closePreview: () => void;
  previewNext: () => void;
  previewPrev: () => void;
  previewHasNext: boolean;
  previewHasPrev: boolean;
  previewMode: MediaLibraryPreviewMode;
  canPreview: boolean;
  resolveTextContent?: (node: MediaNode) => Promise<string>;
  pdfWorkerSrc?: string;

  // mutations
  triggerUpload: () => void;
  uploadFiles: (files: File[], targetFolderId?: string | null) => void;
  retryUpload: (tempId: string) => void;
  dismissUpload: (tempId: string) => void;
  moveTo: (ids: string[], targetFolderId: string | null) => void;
  download: (ids: string[]) => void;
  requestDelete: (ids: string[]) => void;
  canDrop: (draggedIds: string[], targetFolderId: string | null) => boolean;

  // inline rename
  renamingId: string | null;
  renameError: string | null;
  startRename: (id: string) => void;
  submitRename: (id: string, name: string) => void;
  cancelRename: () => void;

  // inline create-folder
  creatingFolder: boolean;
  startCreateFolder: () => void;
  submitCreateFolder: (name: string) => void;
  cancelCreateFolder: () => void;

  // capability flags
  can: {
    upload: boolean;
    move: boolean;
    rename: boolean;
    delete: boolean;
    createFolder: boolean;
    download: boolean;
  };

  // behaviour
  enableInternalDrag: boolean;
  enableUploadDrop: boolean;
  enableContextMenu: boolean;
  virtualizeThreshold: number;

  // dnd transient
  activeDragIds: string[] | null;
  setActiveDragIds: (ids: string[] | null) => void;
  /** True while OS files are dragged over the surface (drives the upload overlay). */
  isDraggingFiles: boolean;
  setDraggingFiles: (v: boolean) => void;

  fileInputRef: RefObject<HTMLInputElement | null>;
}

const MediaLibraryContext = createContext<MediaLibraryContextValue | null>(null);

export function useMediaLibrary(): MediaLibraryContextValue {
  const ctx = useContext(MediaLibraryContext);
  if (!ctx) {
    throw new Error(
      "useMediaLibrary must be used within <MediaLibraryRoot> (or <MediaLibrary01>).",
    );
  }
  return ctx;
}

export { MediaLibraryContext };

function sortByName(a: MediaNode, b: MediaNode): number {
  return a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: "base" });
}

/** Builds the full context value from the root props. */
export function useMediaLibraryStore(
  props: MediaLibraryRootProps,
): MediaLibraryContextValue {
  const {
    nodes: rootNodes,
    onLoadChildren,
    storage,
    onUpload,
    onMove,
    onRename,
    onDelete,
    onCreateFolder,
    onDownload,
    validateRename,
    resolveTextContent,
    pdfWorkerSrc,
    onPreviewOpen,
    onPreviewClose,
    enableUploadDrop = true,
    enableInternalDrag = true,
    enableContextMenu = true,
    preview: previewMode = "both",
    virtualizeThreshold = 120,
    labels: labelOverrides,
  } = props;
  const canPreview = previewMode !== false;

  const labels = useMemo(
    () => ({ ...DEFAULT_MEDIA_LIBRARY_LABELS, ...labelOverrides }),
    [labelOverrides],
  );

  // lazy-merged tree
  const { nodes, ensureLoaded, invalidate, loadingIds, errorIds } = useLazyChildren(
    rootNodes,
    onLoadChildren,
  );

  // current folder (controllable)
  const [currentFolderId, setCurrentFolderId] = useControllableState<string | null>({
    value: props.currentFolderId,
    defaultValue: props.defaultCurrentFolderId ?? null,
    onChange: props.onCurrentFolderChange,
    componentName: "MediaLibrary01",
    valuePropName: "currentFolderId",
  });

  // selection (controllable)
  const [selectedIds, setSelectedIds] = useControllableState<Set<string>>({
    value: props.selectedIds,
    defaultValue: props.defaultSelectedIds ?? new Set<string>(),
    onChange: props.onSelectedChange,
    componentName: "MediaLibrary01",
    valuePropName: "selectedIds",
  });
  const selection = useSelection(selectedIds, setSelectedIds);

  // ui state
  const [filter, setFilter] = useState<MediaFilterCategory>("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [previewId, setPreviewId] = useState<string | null>(null);
  const [clipboard, setClipboard] = useState<MediaClipboard>({ kind: null, ids: [] });
  const [renamingId, setRenamingId] = useState<string | null>(null);
  const [renameError, setRenameError] = useState<string | null>(null);
  const [creatingFolder, setCreatingFolder] = useState(false);
  const [activeDragIds, setActiveDragIds] = useState<string[] | null>(null);
  const [isDraggingFiles, setDraggingFiles] = useState(false);

  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const parentMap = useMemo(() => buildParentMap(nodes), [nodes]);

  // derive current folder + path
  const currentFolder = useMemo(
    () => (currentFolderId == null ? null : findNode(nodes, currentFolderId) ?? null),
    [nodes, currentFolderId],
  );

  const path = useMemo(() => {
    if (currentFolderId == null) return [] as MediaNode[];
    const chain: MediaNode[] = [];
    let cur: string | null | undefined = currentFolderId;
    const seen = new Set<string>();
    while (cur != null && !seen.has(cur)) {
      seen.add(cur);
      const node = findNode(nodes, cur);
      if (!node) break;
      chain.unshift(node);
      cur = node.parentId ?? parentMap.get(cur) ?? null;
    }
    return chain;
  }, [nodes, currentFolderId, parentMap]);

  // children of the current folder
  const currentChildren = useMemo<MediaNode[]>(() => {
    if (currentFolderId == null) return nodes;
    return currentFolder?.children ?? [];
  }, [nodes, currentFolderId, currentFolder]);

  const allFolders = useMemo(
    () => currentChildren.filter((n) => n.type === "folder").sort(sortByName),
    [currentChildren],
  );
  const allFiles = useMemo(
    () => currentChildren.filter((n) => n.type === "file"),
    [currentChildren],
  );

  const filterCounts = useMemo(() => computeFilterCounts(allFiles), [allFiles]);

  const files = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    return allFiles
      .filter((n) => nodeMatchesFilter(n, filter))
      .filter((n) => (q ? n.name.toLowerCase().includes(q) : true))
      .sort(sortByName);
  }, [allFiles, filter, searchQuery]);

  const folders = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    return q ? allFolders.filter((n) => n.name.toLowerCase().includes(q)) : allFolders;
  }, [allFolders, searchQuery]);

  const visibleIds = useMemo(
    () => [...folders.map((n) => n.id), ...files.map((n) => n.id)],
    [folders, files],
  );

  const loadingChildren =
    currentFolderId != null && loadingIds.has(currentFolderId);
  const loadError =
    currentFolderId != null ? (errorIds[currentFolderId] ?? null) : null;

  // ensure current folder children are loaded
  useEffect(() => {
    if (currentFolderId != null) ensureLoaded(currentFolderId);
  }, [currentFolderId, ensureLoaded]);

  // upload
  const onUploadResolved = useCallback(
    (_nodes: MediaNode[], targetFolderId: string | null) => {
      if (targetFolderId != null) invalidate(targetFolderId);
    },
    [invalidate],
  );
  const upload = useUpload(onUpload, onUploadResolved);

  const uploads = useMemo(
    () => upload.uploads.filter((u) => u.targetFolderId === currentFolderId),
    [upload.uploads, currentFolderId],
  );

  // navigation
  const navigateTo = useCallback(
    (folderId: string | null) => {
      setCurrentFolderId(folderId);
      setSearchQuery("");
      setFilter("all");
      selection.clear();
      if (folderId != null) ensureLoaded(folderId);
    },
    [setCurrentFolderId, ensureLoaded, selection],
  );

  const navigateUp = useCallback(() => {
    if (currentFolderId == null) return;
    const parent = currentFolder?.parentId ?? parentMap.get(currentFolderId) ?? null;
    navigateTo(parent);
  }, [currentFolderId, currentFolder, parentMap, navigateTo]);

  const refresh = useCallback(
    (folderId?: string | null) => {
      const target = folderId === undefined ? currentFolderId : folderId;
      invalidate(target);
      if (target != null) ensureLoaded(target);
    },
    [currentFolderId, invalidate, ensureLoaded],
  );

  // preview
  const previewNode = useMemo(
    () => (previewId == null ? null : findNode(nodes, previewId) ?? null),
    [nodes, previewId],
  );
  const previewIndex = previewId == null ? -1 : files.findIndex((f) => f.id === previewId);
  const previewHasNext = previewIndex !== -1 && previewIndex < files.length - 1;
  const previewHasPrev = previewIndex > 0;

  const openPreview = useCallback(
    (id: string) => {
      setPreviewId(id);
      onPreviewOpen?.(id);
    },
    [onPreviewOpen],
  );
  const closePreview = useCallback(() => {
    setPreviewId(null);
    onPreviewClose?.();
  }, [onPreviewClose]);
  const previewNext = useCallback(() => {
    if (previewHasNext) openPreview(files[previewIndex + 1].id);
  }, [previewHasNext, files, previewIndex, openPreview]);
  const previewPrev = useCallback(() => {
    if (previewHasPrev) openPreview(files[previewIndex - 1].id);
  }, [previewHasPrev, files, previewIndex, openPreview]);

  // mutations
  const triggerUpload = useCallback(() => fileInputRef.current?.click(), []);
  const uploadFiles = useCallback(
    (files_: File[], targetFolderId?: string | null) =>
      upload.start(files_, targetFolderId === undefined ? currentFolderId : targetFolderId),
    [upload, currentFolderId],
  );

  const moveTo = useCallback(
    (ids: string[], targetFolderId: string | null) => {
      if (!onMove || ids.length === 0) return;
      if (!canDropInto(ids, targetFolderId, nodes, parentMap)) return;
      onMove(ids, targetFolderId);
      selection.clear();
      if (targetFolderId != null) invalidate(targetFolderId);
      if (currentFolderId != null) invalidate(currentFolderId);
    },
    [onMove, nodes, parentMap, selection, invalidate, currentFolderId],
  );

  const download = useCallback(
    (ids: string[]) => onDownload?.(ids),
    [onDownload],
  );

  const requestDelete = useCallback(
    (ids: string[]) => {
      if (!onDelete || ids.length === 0) return;
      onDelete(ids);
      selection.clear();
      if (currentFolderId != null) invalidate(currentFolderId);
    },
    [onDelete, selection, currentFolderId, invalidate],
  );

  const canDrop = useCallback(
    (draggedIds: string[], targetFolderId: string | null) =>
      canDropInto(draggedIds, targetFolderId, nodes, parentMap),
    [nodes, parentMap],
  );

  // clipboard
  const cut = useCallback((ids: string[]) => {
    if (ids.length > 0) setClipboard({ kind: "cut", ids });
  }, []);
  const paste = useCallback(() => {
    if (clipboard.kind === "cut" && clipboard.ids.length > 0) {
      moveTo(clipboard.ids, currentFolderId);
      setClipboard({ kind: null, ids: [] });
    }
  }, [clipboard, moveTo, currentFolderId]);

  // inline rename
  const startRename = useCallback((id: string) => {
    setRenameError(null);
    setRenamingId(id);
  }, []);
  const cancelRename = useCallback(() => {
    setRenamingId(null);
    setRenameError(null);
  }, []);
  const submitRename = useCallback(
    (id: string, name: string) => {
      const trimmed = name.trim();
      if (!trimmed) {
        cancelRename();
        return;
      }
      const err = validateRename?.(id, trimmed) ?? null;
      if (err) {
        setRenameError(err);
        return;
      }
      onRename?.(id, trimmed);
      setRenamingId(null);
      setRenameError(null);
      if (currentFolderId != null) invalidate(currentFolderId);
    },
    [validateRename, onRename, cancelRename, currentFolderId, invalidate],
  );

  // inline create-folder
  const startCreateFolder = useCallback(() => setCreatingFolder(true), []);
  const cancelCreateFolder = useCallback(() => setCreatingFolder(false), []);
  const submitCreateFolder = useCallback(
    (name: string) => {
      const trimmed = name.trim();
      if (trimmed) onCreateFolder?.(currentFolderId, trimmed);
      setCreatingFolder(false);
      if (currentFolderId != null) invalidate(currentFolderId);
    },
    [onCreateFolder, currentFolderId, invalidate],
  );

  const can = useMemo(
    () => ({
      upload: Boolean(onUpload),
      move: Boolean(onMove),
      rename: Boolean(onRename),
      delete: Boolean(onDelete),
      createFolder: Boolean(onCreateFolder),
      download: Boolean(onDownload),
    }),
    [onUpload, onMove, onRename, onDelete, onCreateFolder, onDownload],
  );

  return useMemo<MediaLibraryContextValue>(
    () => ({
      labels,
      nodes,
      currentFolderId,
      currentFolder,
      path,
      folders,
      files,
      filterCounts,
      uploads,
      loadingChildren,
      loadError,
      filter,
      setFilter,
      searchQuery,
      setSearchQuery,
      storage,
      selectedIds,
      selection,
      visibleIds,
      clipboard,
      cut,
      paste,
      navigateTo,
      navigateUp,
      refresh,
      previewId,
      previewNode,
      openPreview,
      closePreview,
      previewNext,
      previewPrev,
      previewHasNext,
      previewHasPrev,
      previewMode,
      canPreview,
      resolveTextContent,
      pdfWorkerSrc,
      triggerUpload,
      uploadFiles,
      retryUpload: upload.retry,
      dismissUpload: upload.dismiss,
      moveTo,
      download,
      requestDelete,
      canDrop,
      renamingId,
      renameError,
      startRename,
      submitRename,
      cancelRename,
      creatingFolder,
      startCreateFolder,
      submitCreateFolder,
      cancelCreateFolder,
      can,
      enableInternalDrag,
      enableUploadDrop,
      enableContextMenu,
      virtualizeThreshold,
      activeDragIds,
      setActiveDragIds,
      isDraggingFiles,
      setDraggingFiles,
      fileInputRef,
    }),
    [
      labels, nodes, currentFolderId, currentFolder, path, folders, files,
      filterCounts, uploads, loadingChildren, loadError, filter, searchQuery,
      storage, selectedIds, selection, visibleIds, clipboard, cut, paste,
      navigateTo, navigateUp, refresh, previewId, previewNode, openPreview, closePreview,
      previewNext, previewPrev, previewHasNext, previewHasPrev, previewMode, canPreview, resolveTextContent, pdfWorkerSrc,
      triggerUpload, uploadFiles, upload.retry, upload.dismiss, moveTo, download,
      requestDelete, canDrop, renamingId, renameError, startRename, submitRename,
      cancelRename, creatingFolder, startCreateFolder, submitCreateFolder,
      cancelCreateFolder, can, enableInternalDrag, enableUploadDrop,
      enableContextMenu, virtualizeThreshold, activeDragIds, isDraggingFiles,
    ],
  );
}

import { useCallback, useRef } from "react";

export interface ClickModifiers {
  metaKey?: boolean;
  ctrlKey?: boolean;
  shiftKey?: boolean;
}

export interface SelectionApi {
  isSelected: (id: string) => boolean;
  /** Modifier-aware click: plain = replace, ⌘/Ctrl = toggle, Shift = range. */
  handleItemClick: (id: string, mods: ClickModifiers, orderedIds: string[]) => void;
  selectOne: (id: string) => void;
  toggle: (id: string) => void;
  selectAll: (ids: string[]) => void;
  clear: () => void;
}

/**
 * Selection logic over a controllable `Set<string>`. Owns the shift-range
 * anchor. (file-manager's `use-selection` is private — this is a focused,
 * self-contained re-implementation per the GATE-2 Q5 decision.)
 */
export function useSelection(
  selected: Set<string>,
  setSelected: (ids: Set<string>) => void,
): SelectionApi {
  const anchorRef = useRef<string | null>(null);

  const isSelected = useCallback((id: string) => selected.has(id), [selected]);

  const selectOne = useCallback(
    (id: string) => {
      anchorRef.current = id;
      setSelected(new Set([id]));
    },
    [setSelected],
  );

  const toggle = useCallback(
    (id: string) => {
      const next = new Set(selected);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      anchorRef.current = id;
      setSelected(next);
    },
    [selected, setSelected],
  );

  const handleItemClick = useCallback(
    (id: string, mods: ClickModifiers, orderedIds: string[]) => {
      if (mods.shiftKey && anchorRef.current) {
        const a = orderedIds.indexOf(anchorRef.current);
        const b = orderedIds.indexOf(id);
        if (a !== -1 && b !== -1) {
          const [lo, hi] = a < b ? [a, b] : [b, a];
          setSelected(new Set(orderedIds.slice(lo, hi + 1)));
          return;
        }
      }
      if (mods.metaKey || mods.ctrlKey) {
        toggle(id);
        return;
      }
      selectOne(id);
    },
    [selectOne, toggle, setSelected],
  );

  const selectAll = useCallback(
    (ids: string[]) => setSelected(new Set(ids)),
    [setSelected],
  );

  const clear = useCallback(() => {
    anchorRef.current = null;
    setSelected(new Set());
  }, [setSelected]);

  return { isSelected, handleItemClick, selectOne, toggle, selectAll, clear };
}

import { useEffect, useState } from "react";
import type { MediaNode } from "../types";

export interface TextContentState {
  text: string | null;
  loading: boolean;
  error: string | null;
}

/**
 * Fetches text for a text-based file (code/json/txt/markdown). Default path is
 * `fetch(node.url).text()`; a `resolve` override handles auth / signed URLs /
 * transforms. Aborts on node change or unmount.
 */
export function useTextContent(
  node: MediaNode | null,
  enabled: boolean,
  resolve?: (node: MediaNode) => Promise<string>,
): TextContentState {
  const [state, setState] = useState<TextContentState>({
    text: null,
    loading: false,
    error: null,
  });

  // Identity-stable cache keys so an unchanged node doesn't refetch on re-render.
  const nodeId = node?.id ?? null;
  const url = node?.url ?? null;

  useEffect(() => {
    let cancelled = false;
    const controller = new AbortController();

    // All setState calls happen after this microtask yield, so none run
    // synchronously within the effect (avoids cascading-render lint + flashes).
    const run = async () => {
      await Promise.resolve();
      if (cancelled) return;
      if (!enabled || !node) {
        setState({ text: null, loading: false, error: null });
        return;
      }
      setState({ text: null, loading: true, error: null });
      try {
        let text: string;
        if (resolve) {
          text = await resolve(node);
        } else {
          if (!node.url) throw new Error("No URL to fetch");
          const res = await fetch(node.url, { signal: controller.signal });
          if (!res.ok) throw new Error(`HTTP ${res.status}`);
          text = await res.text();
        }
        if (!cancelled) setState({ text, loading: false, error: null });
      } catch (err) {
        if (cancelled) return;
        if ((err as Error).name === "AbortError") return;
        setState({
          text: null,
          loading: false,
          error: (err as Error).message || "Failed to load",
        });
      }
    };

    void run();
    return () => {
      cancelled = true;
      controller.abort();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [nodeId, url, enabled, resolve]);

  return state;
}

import { useCallback, useEffect, useRef, useState } from "react";
import { resolvePreviewKind } from "../lib/preview-kind";
import type { MediaNode, MediaUploadItem, MediaLibraryRootProps } from "../types";

let uploadSeq = 0;
function nextTempId(): string {
  uploadSeq += 1;
  const rand =
    typeof crypto !== "undefined" && "randomUUID" in crypto
      ? crypto.randomUUID()
      : String(uploadSeq);
  return `upl-${uploadSeq}-${rand}`;
}

export interface UploadApi {
  uploads: MediaUploadItem[];
  start: (files: File[], targetFolderId: string | null) => void;
  retry: (tempId: string) => void;
  dismiss: (tempId: string) => void;
}

/**
 * Optimistic upload orchestration. Invokes `onUpload` once per file, shows a
 * placeholder item with a live progress ring, and on resolve hands the real
 * `MediaNode[]` to the store (which is the source of truth) while removing the
 * placeholder. Owns + revokes the object URLs it mints for local previews.
 */
export function useUpload(
  onUpload: MediaLibraryRootProps["onUpload"],
  onResolved: (nodes: MediaNode[], targetFolderId: string | null) => void,
): UploadApi {
  const [uploads, setUploads] = useState<MediaUploadItem[]>([]);
  const ownedUrls = useRef<Set<string>>(new Set());
  const fileMap = useRef<Map<string, { file: File; targetFolderId: string | null }>>(
    new Map(),
  );
  const onResolvedRef = useRef(onResolved);
  useEffect(() => {
    onResolvedRef.current = onResolved;
  });

  const revoke = useCallback((url?: string) => {
    if (url && ownedUrls.current.has(url)) {
      URL.revokeObjectURL(url);
      ownedUrls.current.delete(url);
    }
  }, []);

  const runOne = useCallback(
    (tempId: string, file: File, targetFolderId: string | null) => {
      if (!onUpload) return;
      const progress = (pct: number) =>
        setUploads((prev) =>
          prev.map((u) =>
            u.tempId === tempId
              ? { ...u, pct: Math.max(0, Math.min(100, Math.round(pct))) }
              : u,
          ),
        );
      onUpload([file], targetFolderId, progress)
        .then((nodes) => {
          setUploads((prev) => {
            const item = prev.find((u) => u.tempId === tempId);
            revoke(item?.previewUrl);
            return prev.filter((u) => u.tempId !== tempId);
          });
          fileMap.current.delete(tempId);
          onResolvedRef.current(nodes, targetFolderId);
        })
        .catch((err: unknown) => {
          setUploads((prev) =>
            prev.map((u) =>
              u.tempId === tempId
                ? {
                    ...u,
                    status: "error",
                    error: (err as Error)?.message || "Upload failed",
                  }
                : u,
            ),
          );
        });
    },
    [onUpload, revoke],
  );

  const start = useCallback(
    (files: File[], targetFolderId: string | null) => {
      if (!onUpload || files.length === 0) return;
      const items: MediaUploadItem[] = files.map((file) => {
        const tempId = nextTempId();
        const kind = resolvePreviewKind({
          id: tempId,
          name: file.name,
          type: "file",
          mimeType: file.type,
        } as MediaNode);
        let previewUrl: string | undefined;
        if (file.type.startsWith("image/")) {
          previewUrl = URL.createObjectURL(file);
          ownedUrls.current.add(previewUrl);
        }
        fileMap.current.set(tempId, { file, targetFolderId });
        return {
          tempId,
          name: file.name,
          kind,
          pct: 0,
          status: "uploading" as const,
          previewUrl,
          targetFolderId,
        };
      });
      setUploads((prev) => [...prev, ...items]);
      items.forEach((item) => runOne(item.tempId, fileMap.current.get(item.tempId)!.file, item.targetFolderId));
    },
    [onUpload, runOne],
  );

  const retry = useCallback(
    (tempId: string) => {
      const entry = fileMap.current.get(tempId);
      if (!entry) return;
      setUploads((prev) =>
        prev.map((u) =>
          u.tempId === tempId ? { ...u, status: "uploading", pct: 0, error: undefined } : u,
        ),
      );
      runOne(tempId, entry.file, entry.targetFolderId);
    },
    [runOne],
  );

  const dismiss = useCallback(
    (tempId: string) => {
      setUploads((prev) => {
        const item = prev.find((u) => u.tempId === tempId);
        revoke(item?.previewUrl);
        return prev.filter((u) => u.tempId !== tempId);
      });
      fileMap.current.delete(tempId);
    },
    [revoke],
  );

  // Revoke any outstanding owned URLs on unmount.
  useEffect(() => {
    const owned = ownedUrls.current;
    return () => {
      owned.forEach((url) => URL.revokeObjectURL(url));
      owned.clear();
    };
  }, []);

  return { uploads, start, retry, dismiss };
}

import type { MediaNode } from "../types";

/** Payload carried by a card drag (one or more selected node ids). */
export interface MediaDragData {
  type: "media-node";
  ids: string[];
}

/** Build a `parentId` lookup by walking the (possibly partial) tree. */
export function buildParentMap(nodes: MediaNode[]): Map<string, string | null> {
  const map = new Map<string, string | null>();
  const walk = (list: MediaNode[], parentId: string | null) => {
    for (const n of list) {
      map.set(n.id, n.parentId ?? parentId);
      if (n.children) walk(n.children, n.id);
    }
  };
  walk(nodes, null);
  return map;
}

/** Is `maybeAncestorId` an ancestor of (or equal to) `nodeId`, per the parent map? */
export function isAncestor(
  parentMap: Map<string, string | null>,
  maybeAncestorId: string,
  nodeId: string,
): boolean {
  let cur: string | null | undefined = nodeId;
  const seen = new Set<string>();
  while (cur != null) {
    if (cur === maybeAncestorId) return true;
    if (seen.has(cur)) break; // cycle guard
    seen.add(cur);
    cur = parentMap.get(cur);
  }
  return false;
}

/**
 * Can `draggedIds` drop into `targetFolderId` (null = root)?
 * Rejects: target not a folder; dropping a node onto itself; dropping a folder
 * into its own subtree; a pure no-op (already the current parent of all).
 */
export function canDropInto(
  draggedIds: string[],
  targetFolderId: string | null,
  nodes: MediaNode[],
  parentMap: Map<string, string | null> = buildParentMap(nodes),
): boolean {
  if (draggedIds.length === 0) return false;

  if (targetFolderId !== null) {
    const target = findNode(nodes, targetFolderId);
    if (!target || target.type !== "folder") return false;
    // can't drop a node onto itself, or a folder into its own descendant
    for (const id of draggedIds) {
      if (id === targetFolderId) return false;
      if (isAncestor(parentMap, id, targetFolderId)) return false;
    }
  }

  // reject a pure no-op (every dragged node already lives in the target)
  const allAlreadyHere = draggedIds.every((id) => (parentMap.get(id) ?? null) === targetFolderId);
  if (allAlreadyHere) return false;

  return true;
}

/** Depth-first find by id across the (partial) tree. */
export function findNode(nodes: MediaNode[], id: string): MediaNode | undefined {
  for (const n of nodes) {
    if (n.id === id) return n;
    if (n.children) {
      const hit = findNode(n.children, id);
      if (hit) return hit;
    }
  }
  return undefined;
}

import type { MediaFilterCategory, MediaNode, MediaPreviewKind } from "../types";
import { resolvePreviewKind } from "./preview-kind";

/**
 * Map a preview kind to its type-filter chip (Q4 taxonomy):
 * images / video / pdfs / docs (= code, json, text, markdown + unknown/office).
 */
export function filterCategoryForKind(kind: MediaPreviewKind): Exclude<MediaFilterCategory, "all"> {
  switch (kind) {
    case "image":
      return "images";
    case "video":
      return "video";
    case "pdf":
      return "pdfs";
    default:
      // code | json | text | markdown | unknown (office docs, archives, …)
      return "docs";
  }
}

export function filterCategoryForNode(node: MediaNode): Exclude<MediaFilterCategory, "all"> {
  return filterCategoryForKind(resolvePreviewKind(node));
}

/** Does a file node match the active chip? Folders are never filtered. */
export function nodeMatchesFilter(node: MediaNode, filter: MediaFilterCategory): boolean {
  if (node.type === "folder") return true;
  if (filter === "all") return true;
  return filterCategoryForNode(node) === filter;
}

export type MediaFilterCounts = Record<MediaFilterCategory, number>;

/** Count files per chip for the given (current-folder) file list. */
export function computeFilterCounts(files: MediaNode[]): MediaFilterCounts {
  const counts: MediaFilterCounts = {
    all: 0,
    images: 0,
    video: 0,
    pdfs: 0,
    docs: 0,
  };
  for (const node of files) {
    if (node.type === "folder") continue;
    counts.all += 1;
    counts[filterCategoryForNode(node)] += 1;
  }
  return counts;
}

export const FILTER_ORDER: MediaFilterCategory[] = [
  "all",
  "images",
  "video",
  "pdfs",
  "docs",
];

import { format } from "date-fns";

/** Humanize a byte count → "12.8 GB", "512 KB", "0 B". */
export function formatBytes(bytes: number, decimals = 1): string {
  if (!Number.isFinite(bytes) || bytes <= 0) return "0 B";
  const units = ["B", "KB", "MB", "GB", "TB", "PB"];
  const i = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);
  const value = bytes / Math.pow(1024, i);
  // whole bytes need no decimals; larger units get up to `decimals`
  const str = i === 0 ? String(Math.round(value)) : value.toFixed(decimals).replace(/\.0+$/, "");
  return `${str} ${units[i]}`;
}

/**
 * Compact relative time → "2h ago", "3d ago", "1w ago"; older than ~5 weeks
 * falls back to an absolute "Mar 24" (date-fns). Returns "" for missing input.
 */
export function formatRelativeTime(iso?: string): string {
  if (!iso) return "";
  const then = new Date(iso);
  const ms = then.getTime();
  if (Number.isNaN(ms)) return "";
  const diff = Date.now() - ms;
  if (diff < 0) return "just now";

  const sec = diff / 1000;
  const min = sec / 60;
  const hr = min / 60;
  const day = hr / 24;
  const week = day / 7;

  if (min < 1) return "just now";
  if (min < 60) return `${Math.floor(min)}m ago`;
  if (hr < 24) return `${Math.floor(hr)}h ago`;
  if (day < 7) return `${Math.floor(day)}d ago`;
  if (week < 5) return `${Math.floor(week)}w ago`;
  return format(then, "MMM d");
}

/** Fill a `{token}` template, e.g. tmpl("{used} of {total}", {used:"a",total:"b"}). */
export function fillTemplate(template: string, values: Record<string, string | number>): string {
  return template.replace(/\{(\w+)\}/g, (_, key: string) =>
    key in values ? String(values[key]) : `{${key}}`,
  );
}

import type { MediaNode, MediaPreviewKind } from "../types";

/** Extension → preview kind. Lower-case, no leading dot. */
const EXT_TO_KIND: Record<string, MediaPreviewKind> = {
  // image
  jpg: "image", jpeg: "image", png: "image", gif: "image", webp: "image",
  avif: "image", svg: "image", bmp: "image", ico: "image", heic: "image",
  // video
  mp4: "video", webm: "video", ogv: "video", mov: "video", m4v: "video",
  mkv: "video", avi: "video",
  // pdf
  pdf: "pdf",
  // json
  json: "json", jsonc: "json", geojson: "json",
  // markdown
  md: "markdown", markdown: "markdown", mdx: "markdown",
  // code
  ts: "code", tsx: "code", js: "code", jsx: "code", mjs: "code", cjs: "code",
  html: "code", htm: "code", css: "code", scss: "code", less: "code",
  py: "code", rb: "code", go: "code", rs: "code", java: "code", php: "code",
  swift: "code", kt: "code", c: "code", h: "code", cpp: "code", cc: "code",
  cs: "code", sh: "code", bash: "code", zsh: "code", yaml: "code", yml: "code",
  toml: "code", ini: "code", sql: "code", xml: "code", graphql: "code",
  vue: "code", svelte: "code", dockerfile: "code",
  // plain text
  txt: "text", log: "text", csv: "text", tsv: "text", env: "text",
};

/** Extract the lower-cased extension from `node.ext` or the file name. */
export function extOf(node: { name: string; ext?: string }): string {
  if (node.ext) return node.ext.replace(/^\./, "").toLowerCase();
  const dot = node.name.lastIndexOf(".");
  return dot > 0 ? node.name.slice(dot + 1).toLowerCase() : "";
}

/**
 * Resolve which viewer a file maps to: `mimeType` is authoritative for the
 * broad buckets, `ext` refines/falls back, else `"unknown"` (download-only).
 */
export function resolvePreviewKind(node: MediaNode): MediaPreviewKind {
  if (node.type === "folder") return "unknown";
  const mime = node.mimeType?.toLowerCase();
  const ext = extOf(node);

  if (mime) {
    if (mime.startsWith("image/")) return "image";
    if (mime.startsWith("video/")) return "video";
    if (mime === "application/pdf") return "pdf";
    if (mime === "application/json") return "json";
    if (mime === "text/markdown" || mime === "text/x-markdown") return "markdown";
    if (
      mime === "text/html" ||
      mime === "text/css" ||
      mime === "text/javascript" ||
      mime === "application/javascript" ||
      mime === "application/typescript" ||
      mime === "application/xml" ||
      mime === "text/xml"
    ) {
      return "code";
    }
    if (mime === "text/plain" || mime === "text/csv") {
      // refine with ext when present (e.g. a `.ts` served as text/plain)
      return EXT_TO_KIND[ext] ?? "text";
    }
  }

  return EXT_TO_KIND[ext] ?? "unknown";
}

/** Text-based kinds the lib fetches content for. */
export function isTextKind(kind: MediaPreviewKind): boolean {
  return kind === "code" || kind === "json" || kind === "text" || kind === "markdown";
}

